from itertools import product

def solve():
    s = input().strip()
    n = len(s)

    count = 0

    # Only iterate over x values if X appears in string
    if 'X' in s:
        x_vals = range(10)
    else:
        x_vals = [None]

    for x_val in x_vals:
        # Replace X with x_val
        if x_val is not None:
            t = [str(x_val) if c == 'X' else c for c in s]
        else:
            t = list(s)

        # Find positions of '_'
        blank_positions = [i for i, c in enumerate(t) if c == '_']

        for vals in product(range(10), repeat=len(blank_positions)):
            u = t[:]
            for pos, val in zip(blank_positions, vals):
                u[pos] = str(val)

            # Build number string
            num_str = ''.join(u)

            # Check leading zeros
            if len(num_str) > 1 and num_str[0] == '0':
                continue

            # Check divisibility by 25
            num = int(num_str)
            if num % 25 == 0:
                count += 1

    print(count)

solve()

